<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>2048</title>
<style>
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    background: #131315;
    color: #eee;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Arial, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 16px;
    padding: 20px;
  }
  h1 { margin: 0; font-size: 2.5em; color: #eee4da; letter-spacing: 2px; }
  #hud {
    display: flex;
    align-items: center;
    gap: 12px;
  }
  #score-box {
    background: #1f1f22;
    border-radius: 8px;
    padding: 8px 18px;
    text-align: center;
    min-width: 100px;
  }
  #score-label {
    font-size: 0.7em;
    text-transform: uppercase;
    color: #999;
    letter-spacing: 1px;
  }
  #score {
    font-size: 1.6em;
    font-weight: bold;
    color: #f2b179;
  }
  #reset {
    background: #8f7a66;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 10px 20px;
    font-size: 1em;
    font-weight: bold;
    cursor: pointer;
  }
  #reset:hover { background: #a08a75; }
  #board {
    display: grid;
    grid-template-columns: repeat(4, 90px);
    grid-template-rows: repeat(4, 90px);
    gap: 10px;
    background: #1a1a1d;
    padding: 10px;
    border-radius: 10px;
  }
  .cell {
    width: 90px;
    height: 90px;
    border-radius: 6px;
    background: #232326;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.8em;
    font-weight: bold;
    color: #eee;
    transition: background 0.1s ease;
  }
  .cell[data-v="0"] { background: #232326; color: transparent; }
  .cell[data-v="2"] { background: #2b2b2e; color: #eee; }
  .cell[data-v="4"] { background: #33322e; color: #eee; }
  .cell[data-v="8"] { background: #6b4a2e; color: #fff; }
  .cell[data-v="16"] { background: #7a4a25; color: #fff; }
  .cell[data-v="32"] { background: #8a3f22; color: #fff; }
  .cell[data-v="64"] { background: #99331b; color: #fff; }
  .cell[data-v="128"] { background: #a68c3a; color: #fff; font-size: 1.6em; }
  .cell[data-v="256"] { background: #a68c33; color: #fff; font-size: 1.6em; }
  .cell[data-v="512"] { background: #a6802c; color: #fff; font-size: 1.6em; }
  .cell[data-v="1024"] { background: #a67324; color: #fff; font-size: 1.3em; }
  .cell[data-v="2048"] { background: #c9a227; color: #fff; font-size: 1.3em; }
  #hint { color: #777; font-size: 0.85em; }
</style>
</head>
<body>
  <h1>2048</h1>
  <div id="hud">
    <div id="score-box">
      <div id="score-label">Score</div>
      <div id="score">0</div>
    </div>
    <button id="reset">New Game</button>
  </div>
  <div id="board"></div>
  <div id="hint">Use arrow keys to play</div>

<script>
(function () {
  const SIZE = 4;
  let grid = [];
  let score = 0;

  const boardEl = document.getElementById('board');
  const scoreEl = document.getElementById('score');
  const resetBtn = document.getElementById('reset');

  const cells = [];

  function buildBoardDom() {
    boardEl.innerHTML = '';
    cells.length = 0;
    for (let r = 0; r < SIZE; r++) {
      const row = [];
      for (let c = 0; c < SIZE; c++) {
        const el = document.createElement('div');
        el.className = 'cell';
        el.dataset.v = '0';
        boardEl.appendChild(el);
        row.push(el);
      }
      cells.push(row);
    }
  }

  function render() {
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        const v = grid[r][c];
        const el = cells[r][c];
        el.dataset.v = String(v);
        el.textContent = v === 0 ? '' : String(v);
      }
    }
    scoreEl.textContent = String(score);
  }

  function emptyCells() {
    const list = [];
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        if (grid[r][c] === 0) list.push([r, c]);
      }
    }
    return list;
  }

  function spawnTile() {
    const empties = emptyCells();
    if (empties.length === 0) return false;
    const [r, c] = empties[Math.floor(Math.random() * empties.length)];
    grid[r][c] = Math.random() < 0.9 ? 2 : 4;
    return true;
  }

  function reset() {
    grid = Array.from({ length: SIZE }, () => Array(SIZE).fill(0));
    score = 0;
    spawnTile();
    spawnTile();
    render();
  }

  // Slide + merge a single line (array of length SIZE), moving toward index 0.
  // Returns { line, gained, moved }
  function slideLine(line) {
    const original = line.slice();
    const filtered = line.filter(v => v !== 0);
    const result = [];
    let gained = 0;
    let i = 0;
    while (i < filtered.length) {
      if (i + 1 < filtered.length && filtered[i] === filtered[i + 1]) {
        const merged = filtered[i] * 2;
        result.push(merged);
        gained += merged;
        i += 2;
      } else {
        result.push(filtered[i]);
        i += 1;
      }
    }
    while (result.length < SIZE) result.push(0);
    const moved = result.some((v, idx) => v !== original[idx]);
    return { line: result, gained, moved };
  }

  function getLine(dir, index) {
    const line = [];
    for (let k = 0; k < SIZE; k++) {
      if (dir === 'left' || dir === 'right') line.push(grid[index][k]);
      else line.push(grid[k][index]);
    }
    if (dir === 'right' || dir === 'down') line.reverse();
    return line;
  }

  function setLine(dir, index, line) {
    const out = (dir === 'right' || dir === 'down') ? line.slice().reverse() : line;
    for (let k = 0; k < SIZE; k++) {
      if (dir === 'left' || dir === 'right') grid[index][k] = out[k];
      else grid[k][index] = out[k];
    }
  }

  function move(direction) {
    if (!['left', 'right', 'up', 'down'].includes(direction)) return false;
    let anyMoved = false;
    let totalGain = 0;
    for (let i = 0; i < SIZE; i++) {
      const line = getLine(direction, i);
      const { line: newLine, gained, moved } = slideLine(line);
      if (moved) anyMoved = true;
      totalGain += gained;
      setLine(direction, i, newLine);
    }
    if (anyMoved) {
      score += totalGain;
      spawnTile();
      render();
    }
    return anyMoved;
  }

  function boardArray() {
    return grid.map(row => row.slice());
  }

  function setBoard(arr) {
    grid = arr.map(row => row.slice());
    render();
  }

  window.game = {
    size: SIZE,
    reset,
    move,
    board: boardArray,
    setBoard,
    score: () => score,
  };

  document.addEventListener('keydown', (e) => {
    const map = {
      ArrowLeft: 'left',
      ArrowRight: 'right',
      ArrowUp: 'up',
      ArrowDown: 'down',
    };
    const dir = map[e.key];
    if (dir) {
      e.preventDefault();
      move(dir);
    }
  });

  resetBtn.addEventListener('click', reset);

  buildBoardDom();
  reset();
})();
</script>
</body>
</html>
